#include <stdio.h>
#include <signal.h>
#include <unistd.h>

void sigint_handler(int sig) {
 printf("\nSignal %d received!\n", sig);
}

int main() {
 sigset_t newmask, oldmask, pendmask;
 struct sigaction sa;

 // Setup signal handler
 sa.sa_handler = sigint_handler;
 sigemptyset(&sa.sa_mask);
 sa.sa_flags = 0;
 sigaction(SIGINT, &sa, NULL);

 // Initialize empty signal set
 sigemptyset(&newmask);

 // Add SIGINT to signal set
 sigaddset(&newmask, SIGINT);

 // Block SIGINT and save old mask
 if (sigprocmask(SIG_BLOCK, &newmask, &oldmask) < 0) {
 perror("sigprocmask error");
 return 1;
 }

 printf("SIGINT blocked. Press Ctrl+C - nothing will happen.\n");
 sleep(5);

 // Check if SIGINT is pending
 if (sigpending(&pendmask) == 0) {
 if (sigismember(&pendmask, SIGINT)) {
 printf("SIGINT is pending!\n");
 }
 }

 // Unblock SIGINT - handler will be invoked
 printf("Unblocking SIGINT...\n");
 if (sigprocmask(SIG_SETMASK, &oldmask, NULL) < 0) {
 perror("sigprocmask error");
 return 1;
 }

 return 0;
}

#include <stdio.h>
#include <signal.h>
#include <unistd.h>

volatile int counter = 0;

void alarm_handler(int sig) {
 printf("Alarm triggered! Counter = %d\n", counter);
}

void critical_section_protected() {
 sigset_t block_mask, old_mask;

 // Create signal set with SIGALRM
 sigemptyset(&block_mask);
 sigaddset(&block_mask, SIGALRM);

 // Block SIGALRM (protect critical section)
 sigprocmask(SIG_BLOCK, &block_mask, &old_mask);

 // ===== CRITICAL SECTION START =====
 // This code cannot be interrupted by SIGALRM
 for (int i = 0; i < 1000000; i++) {
 counter++;
 }
 printf("Critical section completed. Counter = %d\n", counter);
 // ===== CRITICAL SECTION END =====

 // Restore previous mask (unblock SIGALRM)
 sigprocmask(SIG_SETMASK, &old_mask, NULL);
}

int main() {
 struct sigaction sa;
 sa.sa_handler = alarm_handler;
 sigemptyset(&sa.sa_mask);
 sa.sa_flags = 0;
 sigaction(SIGALRM, &sa, NULL);

 // Set alarm every 1 second
 alarm(1);

 // Call protected critical section
 critical_section_protected();

 sleep(2);
 return 0;
}

// Standard sigprocmask usage pattern
BEGIN
 DECLARE sigset_t newmask, oldmask

 // Step 1: Initialize empty signal set
 sigemptyset(newmask)

 // Step 2: Add signals to block
 sigaddset(newmask, SIGNAL_1)
 sigaddset(newmask, SIGNAL_2)

 // Step 3: Block signals, save old mask
 result = sigprocmask(SIG_BLOCK, newmask, oldmask)
 IF result == -1 THEN
 PRINT "Error: " + errno
 EXIT
 END IF

 // Step 4: Perform protected operations
 // (signals blocked here)

 // Step 5: Restore old mask (or unblock specific)
 // Option A: Restore completely
 sigprocmask(SIG_SETMASK, oldmask, NULL)

 // Option B: Unblock specific signals only
 // sigprocmask(SIG_UNBLOCK, newmask, NULL)

END
